const update = $json;

let eventType = 'unknown';
let userId = null;
let chatId = null;
let text = null;
let callbackData = null;

if (update.message) {
  eventType = 'message';
  userId = update.message.from.id;
  chatId = update.message.chat.id;
  text = update.message.text || null;
}

if (update.callback_query) {
  eventType = 'callback_query';
  userId = update.callback_query.from.id;
  chatId = update.callback_query.message.chat.id;
  callbackData = update.callback_query.data || null;
  text = update.callback_query.message.text || null;
}

return [
  {
    json: {
      event_type: eventType,
      user_id: userId,
      chat_id: chatId,
      text,
      callback_data: callbackData,
      raw_update: update,
    },
  },
];

const source = $('Code prepare LinkedIn topics prompt').first().json;
const openai = $json;

// При Simplify Output = ON текст обычно здесь:
let rawText =
  openai.output?.[0]?.content?.find(c => c.type === 'output_text')?.text
  || openai.output?.[0]?.content?.[0]?.text
  || openai.text
  || openai.message
  || '';

rawText = rawText.trim();

// На случай если модель вдруг вернула markdown-блок
rawText = rawText
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```$/i, '')
  .trim();

let parsed;

try {
  parsed = JSON.parse(rawText);
} catch (error) {
  throw new Error('Cannot parse LinkedIn topics JSON: ' + error.message + '\nRaw text:\n' + rawText);
}

if (!parsed.topics || !Array.isArray(parsed.topics)) {
  throw new Error('Invalid LLM response: topics array not found');
}

if (parsed.topics.length !== 6) {
  throw new Error(`Expected 6 LinkedIn topics, got ${parsed.topics.length}`);
}

return parsed.topics.map((topic, index) => {
  return {
    json: {
      session_id: source.session_id,
      batch_id: source.batch_id,
      batch_no: source.batch_no,
      topic_no: index + 1,

      title: topic.title,
      explanation: topic.explanation,
      relevance_now: topic.relevance_now,
      source_type: 'linkedin',
      source_company: topic.source_company || null,
      source_url: topic.source_url || null,
      source_signal: topic.source_signal || null,
      score: topic.score || null
    }
  };
});

const rssItems = $input.all().map(item => item.json);

// Берем session/batch из уже сохраненных LinkedIn-тем
const firstLinkedinTopic = $('SQL insert LinkedIn topics').first().json;

// ---------- previous topics anti-duplicate ----------
const previousNode = $('SQL get previous topics for anti-duplicate').first().json;

let previousTopics = previousNode.previous_topics || [];

if (typeof previousTopics === 'string') {
  try {
    previousTopics = JSON.parse(previousTopics);
  } catch (e) {
    previousTopics = [];
  }
}

if (!Array.isArray(previousTopics)) {
  previousTopics = [];
}

const previousTopicsText = previousTopics
  .map((t, index) => {
    return `${index + 1}. [${t.source_type}${t.source_company ? ' / ' + t.source_company : ''}] ${t.title}`;
  })
  .join('\n');

// ---------- current LinkedIn topics in this batch ----------
const currentLinkedInTopics = $('SQL insert LinkedIn topics').all().map(item => item.json);

const currentLinkedInTopicsText = currentLinkedInTopics
  .map((t, index) => {
    return `${index + 1}. ${t.title}`;
  })
  .join('\n');

// ---------- RSS filtering ----------
const keywords = [
  'production',
  'pipeline',
  'development',
  'design',
  'business',
  'studio',
  'outsourcing',
  'co-developer',
  'co-development',
  'external development',
  'live service',
  'live ops',
  'player',
  'engagement',
  'qa',
  'testing',
  'cross-platform',
  'game pass',
  'ai',
  'generative ai',
  'layoffs',
  'scope',
  'plan',
  'narrative',
  'process',
  'publishing',
  'market',
  'risk',
  'cost',
  'sales',
  'art production',
  'unreal',
  'unity',
  'legal',
  'ip',
  'contract',
  'platform',
  'retention',
  'monetization',
  'content',
  'quality'
];

// 1. Дедупликация по link/guid/title
const seen = new Set();
const uniqueItems = [];

for (const article of rssItems) {
  const key = article.link || article.guid || article.title;
  if (!key || seen.has(key)) continue;

  seen.add(key);
  uniqueItems.push(article);
}

// 2. Фильтрация релевантных материалов
const relevant = uniqueItems.filter(article => {
  const text = [
    article.title,
    article.content,
    article.contentSnippet,
    article.link
  ].filter(Boolean).join(' ').toLowerCase();

  return keywords.some(k => text.includes(k));
});

// 3. Ротация источников, чтобы не брать каждый раз одни и те же первые 15 статей
const SELECT_LIMIT = 15;
const batchNo = Number(firstLinkedinTopic.batch_no || 0);

let selected = [];

if (relevant.length > 0) {
  const start = (batchNo * SELECT_LIMIT) % relevant.length;

  const rotated = [
    ...relevant.slice(start),
    ...relevant.slice(0, start),
  ];

  selected = rotated.slice(0, SELECT_LIMIT);
}

// 4. Если релевантных мало или нет — fallback на uniqueItems, тоже с ротацией
if (selected.length === 0 && uniqueItems.length > 0) {
  const start = (batchNo * SELECT_LIMIT) % uniqueItems.length;

  const rotated = [
    ...uniqueItems.slice(start),
    ...uniqueItems.slice(0, start),
  ];

  selected = rotated.slice(0, SELECT_LIMIT);
}

// 5. Собираем corpus для LLM
const internetSignals = selected.map((article, index) => {
  return [
    `[SOURCE ${index + 1}]`,
    `Title: ${article.title || ''}`,
    `Summary: ${article.contentSnippet || article.content || ''}`,
    `URL: ${article.link || ''}`,
    `Date: ${article.isoDate || article.pubDate || ''}`,
    `Author: ${article.creator || article['dc:creator'] || ''}`
  ].join('\n');
}).join('\n\n---\n\n');

if (!internetSignals.trim()) {
  throw new Error('Internet signals are empty after RSS filtering/rotation');
}

const prompt = `
You are a senior B2B content strategist for a game development outsourcing and co-development studio.

Generate exactly 6 strong LinkedIn post topics based on broader internet and game industry signals.

Business context:
- The company works in game development, game art, co-development, outsource production, feature development, live ops, game testing, and full-cycle production.
- The audience includes game founders, producers, studio heads, publishing managers, product owners, and decision-makers in game companies.

Requirements:
- Focus only on game development and adjacent studio services.
- No beginner topics.
- No generic hype.
- No recruiting topics.
- No employer branding topics.
- No event announcement topics.
- Topics must be useful for B2B LinkedIn content.
- Topics must be specific, practical, commercially relevant, and suitable for a game development studio.
- Avoid duplicates and near-duplicates.
- Do not repeat obvious LinkedIn topics about generic co-development unless the internet signal gives a clearly different angle.
- Convert news/signals into practical B2B thought-leadership topics.
- Prefer topics connected to real production pain: cost, quality, timelines, risk, pipelines, live ops, QA, art production, co-development, publishing, market pressure, legal/IP risk, platform shifts, lifecycle extension.
- Source type must always be "internet".
- Score must be from 1 to 10.
- Use only the provided internet signals.

Already shown topics in this Telegram session:
${previousTopicsText || 'No previous topics yet.'}

LinkedIn topics already generated in the current batch:
${currentLinkedInTopicsText || 'No LinkedIn topics in current batch.'}

Anti-duplicate requirements:
- Do not repeat previous topics.
- Do not generate near-duplicates of previous topics.
- Do not repeat the current LinkedIn topics from this batch.
- Do not simply rewrite the same idea with different words.
- If a signal is similar, choose a different business angle, narrower production problem, or different audience.
- The 6 internet topics must add new angles compared to the 6 LinkedIn topics.
- Avoid broad repeated themes about generic co-development, generic QA, generic live ops, or generic art outsourcing unless the selected internet signal gives a clearly new angle.
- If several internet signals are similar to previous topics, prioritize less-used signals from the selected sources.

Return ONLY valid JSON.
No markdown.
No explanations outside JSON.

JSON format:
{
  "topics": [
    {
      "title": "...",
      "explanation": "...",
      "relevance_now": "...",
      "source_type": "internet",
      "source_company": null,
      "source_url": "...",
      "source_signal": "...",
      "score": 8
    }
  ]
}

Internet signals:
${internetSignals}
`;

return [
  {
    json: {
      session_id: firstLinkedinTopic.session_id,
      batch_id: firstLinkedinTopic.batch_id,
      batch_no: firstLinkedinTopic.batch_no,
      source_type: 'internet',

      total_rss_items: rssItems.length,
      unique_items: uniqueItems.length,
      relevant_items: relevant.length,
      selected_items: selected.length,
      selected_rotation_start: relevant.length > 0
        ? (batchNo * SELECT_LIMIT) % relevant.length
        : null,

      internet_signals: internetSignals,

      previous_topics_count: previousTopics.length,
      previous_topics: previousTopics,

      current_linkedin_topics_count: currentLinkedInTopics.length,
      current_linkedin_topics: currentLinkedInTopics,

      prompt
    }
  }
];

