const topics = $input.all().map(item => item.json);
const context = $('Code prepare batch context').first().json;

if (topics.length !== 12) {
  throw new Error(`Expected 12 topics, got ${topics.length}`);
}

topics.sort((a, b) => Number(a.topic_no) - Number(b.topic_no));

const lines = [];

lines.push('Готово. Собрал 12 тем для LinkedIn-поста.');
lines.push('');
lines.push('LinkedIn-сигналы: 1–6');
lines.push('Интернет-сигналы: 7–12');
lines.push('');
lines.push('Выбери тему:');
lines.push('');

for (const topic of topics) {
  const sourceLabel = topic.source_type === 'linkedin' ? 'LinkedIn' : 'Internet';

  lines.push(`${topic.topic_no}. ${topic.title}`);
  lines.push(`Источник: ${sourceLabel}${topic.source_company ? ` / ${topic.source_company}` : ''}`);
  //lines.push(`Почему актуально: ${topic.relevance_now}`);
  lines.push('');
}

// Кнопки выбора тем: 4 ряда по 3 кнопки
const topicButtons = [];
for (let i = 0; i < topics.length; i += 3) {
