const normalized = $('Normalize Telegram Update').first().json;
const callbackData = normalized.callback_data || '';

if (!callbackData.startsWith('lang:')) {
  throw new Error(`Invalid language callback_data: ${callbackData}`);
}

const langCode = callbackData.replace('lang:', '');

const languageMap = {
  en: 'English',
  ru: 'Russian',
};

const language = languageMap[langCode];

if (!language) {
  throw new Error(`Unsupported language: ${langCode}`);
}

return [
  {
    json: {
      telegram_user_id: normalized.user_id,
      chat_id: normalized.chat_id,
      callback_data: callbackData,
      language_code: langCode,
      language,
    }
  }
];

