  throw new Error('No LinkedIn chunks found in DB. Run Refresh LinkedIn Corpus workflow first.');
}

const session = $('SQL create session').first().json;
const batch = $('SQL create topic_batch').first().json;

const linkedinSignals = chunks.map((chunk) => {
  return [
    `[SOURCE_COMPANY: ${chunk.company_name}]`,
    `[CATEGORY: ${chunk.category || 'unknown'}]`,
    chunk.chunk_text
  ].join('\n');
}).join('\n\n---\n\n');

const companyStats = {};

for (const chunk of chunks) {
  const key = chunk.company_name || 'unknown';
  companyStats[key] = (companyStats[key] || 0) + 1;
}

return [
  {
    json: {
      session_id: session.id,
      telegram_user_id: session.telegram_user_id,
      chat_id: session.chat_id,

      batch_id: batch.id,
      batch_no: batch.batch_no,
      source_type: 'linkedin',

      linkedin_signals: linkedinSignals,
      selected_chunks: chunks.length,
      linkedin_chunks: chunks,

      parsed_pages: null,
      used_chunks: chunks.length,
      final_corpus_size: linkedinSignals.length,
      used_fallback: false,
      company_stats: companyStats
    }
  }
];
